     }
   }

+  // For implication/subset reasoning, also recognize masked equality and
+  // inequality compares on negative power-of-two masks. This lets us model
+  // `(x & -2) == 2` as the exact range [2, 4) over x.
+  auto TryMatchMaskedICmp = [&](CmpPredicate Pred, Value *&V, const APInt *C,
+                                const APInt *&Mask, bool &Matched) {
+    if (Matched || (Pred != ICmpInst::ICMP_EQ && Pred != ICmpInst::ICMP_NE))
+      return;
+
+    Value *X;
+    if (!match(V, m_OneUse(m_And(m_Value(X), m_NegatedPower2(Mask)))))
+      return;
+
+    // The compared constant must be aligned to the mask.
+    if ((*C & ~*Mask) != *C)
+      return;
+
+    Matched = true;
+    V = X;
+  };
+
+  if (V1 != V2) {
+    TryMatchMaskedICmp(Pred1, V1, C1, Mask1, MatchedAnd1);
+    TryMatchMaskedICmp(Pred2, V2, C2, Mask2, MatchedAnd2);
+  }
+
   if (V1 != V2)
     return nullptr;

+  auto GetTrueRange = [&](CmpPredicate Pred, const APInt &C,
+                          bool IsMasked, const APInt *Mask) {
+    if (IsMasked) {
+      ConstantRange CR(C, C - *Mask);
+      return Pred == ICmpInst::ICMP_EQ ? CR : CR.inverse();
+    }
+    return ConstantRange::makeExactICmpRegion(Pred, C);
+  };
+
+  ConstantRange TrueCR1 = GetTrueRange(Pred1, *C1, MatchedAnd1, Mask1);
+  if (Offset1)
+    TrueCR1 = TrueCR1.subtract(*Offset1);
+
+  ConstantRange TrueCR2 = GetTrueRange(Pred2, *C2, MatchedAnd2, Mask2);
+  if (Offset2)
+    TrueCR2 = TrueCR2.subtract(*Offset2);
+
+  // If one compare implies the other, return the original compare directly.
+  // For &&, choose the stronger/narrower condition.
+  // For ||, choose the weaker/wider condition.
+  if (TrueCR1.contains(TrueCR2))
+    return IsAnd ? static_cast<Value *>(ICmp2) : static_cast<Value *>(ICmp1);
+  if (TrueCR2.contains(TrueCR1))
+    return IsAnd ? static_cast<Value *>(ICmp1) : static_cast<Value *>(ICmp2);
+
   ConstantRange CR1 =
       MatchedAnd1
           ? ConstantRange(*C1, *C1 - *Mask1)
@@ -1419,6 +1470,7 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
   return Builder.CreateICmp(NewPred, NewV, ConstantInt::get(Ty, NewC));
 }

